import{_ as e,c as o,a3 as t,o as i}from"./chunks/framework.C681U02K.js";const m=JSON.parse('{"title":"PTAdmin/Easy","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),r={name:"guide/index.md"};function l(n,a,d,s,c,h){return i(),o("div",null,a[0]||(a[0]=[t('<h1 id="ptadmin-easy" tabindex="-1">PTAdmin/Easy <a class="header-anchor" href="#ptadmin-easy" aria-label="Permalink to &quot;PTAdmin/Easy&quot;">​</a></h1><h2 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h2><p>PTAdmin/Easy 是一个快速实现<code>CURD</code>的开发库，可用于 <strong>动态自定义</strong>、<strong>配置化</strong> 数据表结构的业务场景开发。 搭配<a href="https://www.pangtou.com" target="_blank" rel="noreferrer">PTAdmin</a> 后台管理框架，可以方便快速地实现业务需求。</p><h2 id="基础信息" tabindex="-1">基础信息 <a class="header-anchor" href="#基础信息" aria-label="Permalink to &quot;基础信息&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>PTAdmin/Easy 主要根据模型和模型字段两个进行开发处理。</p></div><ul><li>模型【mod】</li></ul><blockquote><p>对应数据表为mods, 用于存储模型信息</p></blockquote><ul><li>模型字段【mod_field】</li></ul><blockquote><p>对应数据表为mod_fields, 用于存储模型字段信息</p></blockquote><h2 id="应用场景" tabindex="-1">应用场景 <a class="header-anchor" href="#应用场景" aria-label="Permalink to &quot;应用场景&quot;">​</a></h2><h3 id="cms内容管理类系统" tabindex="-1">CMS内容管理类系统 <a class="header-anchor" href="#cms内容管理类系统" aria-label="Permalink to &quot;CMS内容管理类系统&quot;">​</a></h3><blockquote><p>在开发中，我们通常需要实现一个内容管理系统，比如：文章管理、评论管理、用户管理、分类管理等。 而大部分并没有太多的特性，PTAdmin/Easy 提供了快速实现这些功能。</p></blockquote><h3 id="问卷调查类系统" tabindex="-1">问卷调查类系统 <a class="header-anchor" href="#问卷调查类系统" aria-label="Permalink to &quot;问卷调查类系统&quot;">​</a></h3><blockquote><p>问卷类需求在开发中是比较常见的业务要求，搭配上PTAdmin/Easy 可以通过自定义生成问卷表单，快速实现问卷调查功能。 后期我们也将扩展问卷统计方面的需求。</p></blockquote><h3 id="其他场景" tabindex="-1">其他场景 <a class="header-anchor" href="#其他场景" aria-label="Permalink to &quot;其他场景&quot;">​</a></h3><p>待补充</p>',16)]))}con